import{_ as s,C as n,o as t,c as B,a2 as r,b as l,w as a,a as o,E as d,a3 as E}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"CI/CD 最佳实践与流水线设计","description":"","frontmatter":{"title":"CI/CD 最佳实践与流水线设计","module":"cicd","difficulty":"intermediate","interviewFrequency":"medium","tags":["CI/CD","最佳实践","流水线"],"codeExample":"06-devops/cicd-examples/","relatedEntries":["/6-devops/6.2-cicd/01-jenkins","/6-devops/6.1-docker-k8s/09-k8s-deploy"],"prerequisites":["/6-devops/6.2-cicd/01-jenkins"],"estimatedTime":"30min"},"headers":[],"relativePath":"6-devops/6.2-cicd/04-best-practices.md","filePath":"6-devops/6.2-cicd/04-best-practices.md","lastUpdated":null}'),A={name:"6-devops/6.2-cicd/04-best-practices.md"};function c(h,e,D,u,p,C){const i=n("Mermaid");return t(),B("div",null,[e[2]||(e[2]=r('<h1 id="ci-cd-最佳实践与流水线设计" tabindex="-1">CI/CD 最佳实践与流水线设计 <a class="header-anchor" href="#ci-cd-最佳实践与流水线设计" aria-label="Permalink to &quot;CI/CD 最佳实践与流水线设计&quot;">​</a></h1><h2 id="概念说明" tabindex="-1">概念说明 <a class="header-anchor" href="#概念说明" aria-label="Permalink to &quot;概念说明&quot;">​</a></h2><p>良好的 CI/CD 流水线设计能显著提升团队的交付效率和代码质量。本节总结 Java 项目 CI/CD 的最佳实践。</p><h2 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h2><h3 id="标准流水线设计" tabindex="-1">标准流水线设计 <a class="header-anchor" href="#标准流水线设计" aria-label="Permalink to &quot;标准流水线设计&quot;">​</a></h3>',5)),(t(),l(E,null,{default:a(()=>[d(i,{id:"mermaid-15",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%22%E4%BB%A3%E7%A0%81%E6%8F%90%E4%BA%A4%22%5D%20--%3E%20B%5B%22%E7%BC%96%E8%AF%91%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22%E5%8D%95%E5%85%83%E6%B5%8B%E8%AF%95%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22%E4%BB%A3%E7%A0%81%E6%89%AB%E6%8F%8F%22%5D%0A%20%20%20%20D%20--%3E%20E%5B%22%E6%9E%84%E5%BB%BA%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20E%20--%3E%20F%5B%22%E9%83%A8%E7%BD%B2%20Staging%22%5D%0A%20%20%20%20F%20--%3E%20G%5B%22%E9%9B%86%E6%88%90%E6%B5%8B%E8%AF%95%22%5D%0A%20%20%20%20G%20--%3E%20H%5B%22%E4%BA%BA%E5%B7%A5%E5%AE%A1%E6%89%B9%22%5D%0A%20%20%20%20H%20--%3E%20I%5B%22%E9%83%A8%E7%BD%B2%20Production%22%5D%0A%0A%20%20%20%20style%20A%20fill%3A%23e1f5fe%0A%20%20%20%20style%20D%20fill%3A%23fff3e0%0A%20%20%20%20style%20H%20fill%3A%23fce4ec%0A%20%20%20%20style%20I%20fill%3A%23e8f5e9%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[o(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=r('<h3 id="分支策略与流水线" tabindex="-1">分支策略与流水线 <a class="header-anchor" href="#分支策略与流水线" aria-label="Permalink to &quot;分支策略与流水线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>分支</th><th>触发条件</th><th>流水线内容</th></tr></thead><tbody><tr><td>feature/*</td><td>Push/PR</td><td>编译 + 单元测试</td></tr><tr><td>develop</td><td>Merge</td><td>编译 + 测试 + 代码扫描 + 部署 Dev</td></tr><tr><td>release/*</td><td>Tag</td><td>编译 + 测试 + 构建镜像 + 部署 Staging</td></tr><tr><td>main</td><td>Merge</td><td>全流程 + 部署 Production</td></tr><tr><td>hotfix/*</td><td>Push</td><td>编译 + 测试 + 快速部署</td></tr></tbody></table><h3 id="核心最佳实践" tabindex="-1">核心最佳实践 <a class="header-anchor" href="#核心最佳实践" aria-label="Permalink to &quot;核心最佳实践&quot;">​</a></h3><p><strong>1. 快速反馈</strong></p><ul><li>流水线总时长控制在 10 分钟以内</li><li>单元测试并行执行</li><li>使用缓存加速构建（Maven 依赖、Docker 层缓存）</li></ul><p><strong>2. 制品管理</strong></p><ul><li>构建一次，部署多次（同一镜像部署到不同环境）</li><li>使用语义化版本号标记镜像</li><li>制品仓库统一管理（Nexus/Harbor）</li></ul><p><strong>3. 环境一致性</strong></p><ul><li>使用 Docker 保证构建环境一致</li><li>配置外部化（环境变量/配置中心）</li><li>Infrastructure as Code（Terraform/Ansible）</li></ul><p><strong>4. 安全实践</strong></p><ul><li>Secrets 加密存储，不硬编码</li><li>依赖漏洞扫描（OWASP Dependency Check）</li><li>镜像安全扫描（Trivy）</li><li>最小权限原则</li></ul><h3 id="java-项目特有实践" tabindex="-1">Java 项目特有实践 <a class="header-anchor" href="#java-项目特有实践" aria-label="Permalink to &quot;Java 项目特有实践&quot;">​</a></h3>',12)),(t(),l(E,null,{default:a(()=>[d(i,{id:"mermaid-182",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%22Java%20CI%2FCD%20%E7%89%B9%E6%9C%89%E5%AE%9E%E8%B7%B5%22%5D%20--%3E%20B%5B%22Maven%20%E6%9E%84%E5%BB%BA%E4%BC%98%E5%8C%96%22%5D%0A%20%20%20%20A%20--%3E%20C%5B%22%E6%B5%8B%E8%AF%95%E7%AD%96%E7%95%A5%22%5D%0A%20%20%20%20A%20--%3E%20D%5B%22Docker%20%E4%BC%98%E5%8C%96%22%5D%0A%0A%20%20%20%20B%20--%3E%20B1%5B%22%E4%BE%9D%E8%B5%96%E7%BC%93%E5%AD%98%22%5D%0A%20%20%20%20B%20--%3E%20B2%5B%22%E5%A2%9E%E9%87%8F%E7%BC%96%E8%AF%91%22%5D%0A%20%20%20%20B%20--%3E%20B3%5B%22%E5%B9%B6%E8%A1%8C%E6%9E%84%E5%BB%BA%20-T%204%22%5D%0A%0A%20%20%20%20C%20--%3E%20C1%5B%22%E5%8D%95%E5%85%83%E6%B5%8B%E8%AF%95%EF%BC%88%E5%BF%85%E9%A1%BB%EF%BC%89%22%5D%0A%20%20%20%20C%20--%3E%20C2%5B%22%E9%9B%86%E6%88%90%E6%B5%8B%E8%AF%95%EF%BC%88Staging%EF%BC%89%22%5D%0A%20%20%20%20C%20--%3E%20C3%5B%22%E6%80%A7%E8%83%BD%E6%B5%8B%E8%AF%95%EF%BC%88%E5%8F%AF%E9%80%89%EF%BC%89%22%5D%0A%0A%20%20%20%20D%20--%3E%20D1%5B%22%E5%A4%9A%E9%98%B6%E6%AE%B5%E6%9E%84%E5%BB%BA%22%5D%0A%20%20%20%20D%20--%3E%20D2%5B%22JRE%20%E5%9F%BA%E7%A1%80%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20D%20--%3E%20D3%5B%22%E5%88%86%E5%B1%82%20JAR%22%5D%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[o(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=r('<h2 id="常见面试题" tabindex="-1">常见面试题 <a class="header-anchor" href="#常见面试题" aria-label="Permalink to &quot;常见面试题&quot;">​</a></h2><h3 id="q1-如何设计一个好的-ci-cd-流水线" tabindex="-1">Q1: 如何设计一个好的 CI/CD 流水线？ <a class="header-anchor" href="#q1-如何设计一个好的-ci-cd-流水线" aria-label="Permalink to &quot;Q1: 如何设计一个好的 CI/CD 流水线？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥</p><p><strong>标准答案</strong>：</p><p>好的流水线遵循以下原则：1）快速反馈（10 分钟内完成）；2）构建一次部署多次（同一制品）；3）环境一致性（Docker 化）；4）渐进式验证（单元测试→集成测试→性能测试）；5）安全左移（代码扫描、依赖检查前置）；6）生产部署需要人工审批。标准阶段：编译→测试→代码扫描→构建镜像→部署 Staging→集成测试→审批→部署 Production。</p><h3 id="q2-ci-cd-中如何处理数据库变更" tabindex="-1">Q2: CI/CD 中如何处理数据库变更？ <a class="header-anchor" href="#q2-ci-cd-中如何处理数据库变更" aria-label="Permalink to &quot;Q2: CI/CD 中如何处理数据库变更？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥</p><p><strong>标准答案</strong>：</p><p>使用数据库迁移工具（Flyway/Liquibase）管理 Schema 变更。迁移脚本纳入版本控制，在部署流水线中自动执行。关键原则：只增不删（向后兼容）、先迁移后部署、支持回滚。大表变更使用 Online DDL 或 gh-ost 工具避免锁表。</p><h3 id="q3-如何实现零停机部署" tabindex="-1">Q3: 如何实现零停机部署？ <a class="header-anchor" href="#q3-如何实现零停机部署" aria-label="Permalink to &quot;Q3: 如何实现零停机部署？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥</p><p><strong>标准答案</strong>：</p><p>三种方案：1）滚动更新（K8s 默认）：逐步替换旧 Pod，配合健康检查和优雅停机；2）蓝绿部署：同时运行新旧版本，切换流量；3）金丝雀发布：先将少量流量导向新版本，验证后逐步扩大。关键配合：应用支持优雅停机（处理完当前请求再退出）、数据库变更向后兼容、健康检查就绪后才接收流量。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://continuousdelivery.com/" target="_blank" rel="noreferrer">Continuous Delivery - Jez Humble</a></li></ul>',15))])}const f=s(A,[["render",c]]);export{m as __pageData,f as default};
